document.addEventListener('DOMContentLoaded', () => { const cursor = document.querySelector('.cursor'); const follower = document.querySelector('.cursor-follower'); const links = document.querySelectorAll('a, button, .filter-btn, .gallery-item, .btn-back'); let mouseX = 0; let mouseY = 0; let cursorX = 0; let cursorY = 0; let followerX = 0; let followerY = 0; window.addEventListener('mousemove', (e) => { mouseX = e.clientX; mouseY = e.clientY; if (cursor) cursor.style.opacity = '1'; if (follower) follower.style.opacity = '1'; }); const animate = () => { followerX += (mouseX - followerX) * 0.15; followerY += (mouseY - followerY) * 0.15; if (cursor) { cursor.style.transform = `translate3d(${mouseX}px, ${mouseY}px, 0) translate(-50%, -50%)`; } if (follower) { follower.style.transform = `translate3d(${followerX}px, ${followerY}px, 0) translate(-50%, -50%)`; } requestAnimationFrame(animate); }; animate(); const handleMouseEnter = (e) => { const target = e.target.closest('a, button, .filter-btn, .gallery-item, .btn-back, .project-card'); if (target) { if (follower) { follower.style.width = '80px'; follower.style.height = '80px'; follower.style.background = 'rgba(0, 71, 171, 0.05)'; follower.style.borderColor = 'transparent'; } if (cursor) { cursor.style.width = '12px'; cursor.style.height = '12px'; } } }; const handleMouseLeave = (e) => { const target = e.target.closest('a, button, .filter-btn, .gallery-item, .btn-back, .project-card'); if (target) { if (follower) { follower.style.width = '40px'; follower.style.height = '40px'; follower.style.background = 'transparent'; follower.style.borderColor = 'var(--color-primary)'; } if (cursor) { cursor.style.width = '8px'; cursor.style.height = '8px'; } } }; document.addEventListener('mouseover', handleMouseEnter); document.addEventListener('mouseout', handleMouseLeave); document.addEventListener('mouseleave', () => { if (cursor) cursor.style.opacity = '0'; if (follower) follower.style.opacity = '0'; }); document.addEventListener('mouseenter', () => { if (cursor) cursor.style.opacity = '1'; if (follower) follower.style.opacity = '1'; }); const navbar = document.querySelector('.navbar'); window.addEventListener('scroll', () => { if (window.scrollY > 50) { navbar?.classList.add('scrolled'); } else { navbar?.classList.remove('scrolled'); } }); const menuToggle = document.querySelector('.menu-toggle'); const navLinks = document.querySelector('.nav-links'); menuToggle?.addEventListener('click', () => { if (!navLinks) return; navLinks.classList.toggle('active'); if (navLinks.classList.contains('active')) { navLinks.style.display = 'flex'; navLinks.style.flexDirection = 'column'; navLinks.style.position = 'fixed'; navLinks.style.top = '70px'; navLinks.style.left = '0'; navLinks.style.width = '100%'; navLinks.style.background = 'var(--color-bg)'; navLinks.style.padding = '2rem'; } else { navLinks.style.display = ''; } }); const scrollObserverOptions = { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }; const revealObserver = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { entry.target.classList.add('visible'); revealObserver.unobserve(entry.target); } }); }, scrollObserverOptions); document.querySelectorAll('.fade-in-up, .project-card, .expertise-item, .category-block').forEach(el => { if (!el.classList.contains('fade-in-up')) el.classList.add('fade-in-up'); revealObserver.observe(el); }); document.querySelectorAll('.nav-item').forEach(anchor => { anchor.addEventListener('click', function(e) { const href = this.getAttribute('href'); if (href.startsWith('#')) { e.preventDefault(); const targetElement = document.querySelector(href); if (targetElement) { const offset = 80; const bodyRect = document.body.getBoundingClientRect().top; const elementRect = targetElement.getBoundingClientRect().top; const elementPosition = elementRect - bodyRect; const offsetPosition = elementPosition - offset; window.scrollTo({ top: offsetPosition, behavior: 'smooth' }); } } }); }); const magneticBtns = document.querySelectorAll('.btn-main'); magneticBtns.forEach(btn => { btn.addEventListener('mousemove', function(e) { const position = this.getBoundingClientRect(); const x = e.pageX - position.left - position.width / 2; const y = e.pageY - position.top - position.height / 2; this.style.transform = `translate(${x * 0.3}px, ${y * 0.5}px)`; }); btn.addEventListener('mouseout', function() { this.style.transform = 'translate(0px, 0px)'; }); }); const blobs = document.querySelectorAll('.blob'); window.addEventListener('scroll', () => { const scrolled = window.pageYOffset; blobs.forEach((blob, index) => { const speed = (index + 1) * 0.2; blob.style.transform = `translateY(${scrolled * speed}px)`; }); }); window.addEventListener('load', () => { document.body.classList.remove('loading'); document.body.classList.add('loaded'); const heroElements = document.querySelectorAll('.hero-meta, .hero-title, .hero-subtitle, .hero-actions'); heroElements.forEach((el, i) => { setTimeout(() => { el.classList.add('visible'); }, i * 200); }); }); const filterButtons = document.querySelectorAll('.filter-btn'); const projectCards = document.querySelectorAll('.project-card[data-category="architecture"]'); filterButtons.forEach(btn => { btn.addEventListener('click', () => { filterButtons.forEach(b => b.classList.remove('active')); btn.classList.add('active'); const filterValue = btn.getAttribute('data-filter'); projectCards.forEach((card, index) => { const projectType = card.getAttribute('data-type'); if (filterValue === 'all' || projectType === filterValue) { card.classList.remove('hidden'); card.style.position = 'relative'; setTimeout(() => { card.classList.add('visible'); }, index * 50); } else { card.classList.add('hidden'); setTimeout(() => { if (card.classList.contains('hidden')) { card.style.position = 'absolute'; } }, 600); } }); }); }); const createLightbox = () => { const lightbox = document.createElement('div'); lightbox.id = 'lightbox'; lightbox.className = 'lightbox'; lightbox.innerHTML = ` <div class="lightbox-content"> <img src="" alt="Lightbox Image"> <button class="lightbox-close" aria-label="Close lightbox">&times;</button> <button class="lightbox-prev" aria-label="Previous image"><i class="fas fa-chevron-left"></i></button> <button class="lightbox-next" aria-label="Next image"><i class="fas fa-chevron-right"></i></button> </div> `; document.body.appendChild(lightbox); return lightbox; }; const lightbox = document.getElementById('lightbox') || createLightbox(); const lightboxImg = lightbox.querySelector('img'); const lightboxClose = lightbox.querySelector('.lightbox-close'); const lightboxPrev = lightbox.querySelector('.lightbox-prev'); const lightboxNext = lightbox.querySelector('.lightbox-next'); let currentGallery = []; let currentIndex = 0; const openLightbox = (index, gallery) => { currentGallery = gallery; currentIndex = index; lightboxImg.src = currentGallery[currentIndex].src; lightbox.classList.add('active'); document.body.style.overflow = 'hidden'; }; const closeLightbox = () => { lightbox.classList.remove('active'); document.body.style.overflow = ''; }; const nextImage = () => { currentIndex = (currentIndex + 1) % currentGallery.length; lightboxImg.style.opacity = '0'; setTimeout(() => { lightboxImg.src = currentGallery[currentIndex].src; lightboxImg.style.opacity = '1'; }, 200); }; const prevImage = () => { currentIndex = (currentIndex - 1 + currentGallery.length) % currentGallery.length; lightboxImg.style.opacity = '0'; setTimeout(() => { lightboxImg.src = currentGallery[currentIndex].src; lightboxImg.style.opacity = '1'; }, 200); }; document.addEventListener('click', (e) => { const galleryItem = e.target.closest('.gallery-item img'); if (galleryItem) { const gallery = Array.from(document.querySelectorAll('.gallery-item img')); const index = gallery.indexOf(galleryItem); openLightbox(index, gallery); } if (e.target.closest('.lightbox-close') || (e.target.id === 'lightbox' && !e.target.closest('.lightbox-content img'))) { closeLightbox(); } if (e.target.closest('.lightbox-next')) { nextImage(); } if (e.target.closest('.lightbox-prev')) { prevImage(); } }); document.addEventListener('keydown', (e) => { if (!lightbox.classList.contains('active')) return; if (e.key === 'Escape') closeLightbox(); if (e.key === 'ArrowRight') nextImage(); if (e.key === 'ArrowLeft') prevImage(); }); });